-- anthropic_messages
DROP TABLE IF EXISTS `anthropic_messages`;
CREATE TABLE anthropic_messages (
    conversation_uuid    VARCHAR(64)  NOT NULL,
    message_uuid         VARCHAR(64)  NOT NULL,
    parent_message_uuid  VARCHAR(64),
    sender               VARCHAR(32),
    text                 LONGTEXT,
    created_at           VARCHAR(40),
    updated_at           VARCHAR(40),
    raw_json             JSON         NOT NULL,
    source               VARCHAR(16)  NOT NULL DEFAULT 'export',
    last_seen_at         VARCHAR(40)  NOT NULL,
    PRIMARY KEY (message_uuid)
);

INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000001-1701-4d00-8000-00000000c001', '10000001-1701-4d00-8000-000000010001', NULL, 'human', 'Computer, why does the replicator give weak Earl Grey at quarters preset 4?', '2369-04-12T09:15:00.000000+00:00', '2369-04-12T09:15:00.000000+00:00', '{"created_at":"2369-04-12T09:15:00.000000+00:00","index":0,"parent_message_uuid":null,"sender":"human","text":"Computer, why does the replicator give weak Earl Grey at quarters preset 4?","truncated":false,"updated_at":"2369-04-12T09:15:00.000000+00:00","uuid":"10000001-1701-4d00-8000-000000010001"}', 'export', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000001-1701-4d00-8000-00000000c001', '10000002-1701-4d00-8000-000000010002', '10000001-1701-4d00-8000-000000010001', 'assistant', 'Preset 4 caps tannin extraction at 38%. Try preset 7 (the canonical "hot") which targets 52% and 88°C.', '2369-04-12T09:15:30.000000+00:00', '2369-04-12T09:15:30.000000+00:00', '{"created_at":"2369-04-12T09:15:30.000000+00:00","index":1,"parent_message_uuid":"10000001-1701-4d00-8000-000000010001","sender":"assistant","text":"Preset 4 caps tannin extraction at 38%. Try preset 7 (the canonical \\"hot\\") which targets 52% and 88°C.","truncated":false,"updated_at":"2369-04-12T09:15:30.000000+00:00","uuid":"10000002-1701-4d00-8000-000000010002"}', 'export', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000001-1701-4d00-8000-00000000c001', '10000003-1701-4d00-8000-000000010003', '10000002-1701-4d00-8000-000000010002', 'human', 'Engage. Thank you.', '2369-04-12T09:18:30.000000+00:00', '2369-04-12T09:18:30.000000+00:00', '{"created_at":"2369-04-12T09:18:30.000000+00:00","index":2,"parent_message_uuid":"10000002-1701-4d00-8000-000000010002","sender":"human","text":"Engage. Thank you.","truncated":false,"updated_at":"2369-04-12T09:18:30.000000+00:00","uuid":"10000003-1701-4d00-8000-000000010003"}', 'export', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000002-1701-4d00-8000-00000000c002', '20000001-1701-4d00-8000-000000020001', NULL, 'human', 'Attached the conduit telemetry. Why is conduit 17 oscillating at 0.4 Hz?', '2369-04-13T14:02:00.000000+00:00', '2369-04-13T14:02:00.000000+00:00', '{"created_at":"2369-04-13T14:02:00.000000+00:00","index":0,"parent_message_uuid":null,"sender":"human","text":"Attached the conduit telemetry. Why is conduit 17 oscillating at 0.4 Hz?","truncated":false,"updated_at":"2369-04-13T14:02:00.000000+00:00","uuid":"20000001-1701-4d00-8000-000000020001"}', 'export', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000002-1701-4d00-8000-00000000c002', '20000002-1701-4d00-8000-000000020002', '20000001-1701-4d00-8000-000000020001', 'assistant', 'The 0.4Hz is a beat frequency between the EPS regulator (750.0Hz) and the dilithium chamber harmonic (750.4Hz). Re-tune the regulator to 750.2Hz to null it out.', '2369-04-13T14:05:11.000000+00:00', '2369-04-13T14:05:11.000000+00:00', '{"created_at":"2369-04-13T14:05:11.000000+00:00","index":1,"parent_message_uuid":"20000001-1701-4d00-8000-000000020001","sender":"assistant","text":"The 0.4Hz is a beat frequency between the EPS regulator (750.0Hz) and the dilithium chamber harmonic (750.4Hz). Re-tune the regulator to 750.2Hz to null it out.","truncated":false,"updated_at":"2369-04-13T14:05:11.000000+00:00","uuid":"20000002-1701-4d00-8000-000000020002"}', 'export', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000003-1701-4d00-8000-00000000c003', '30000001-1701-4d00-8000-000000030001', NULL, 'human', 'Look up the Klingon greeting "nuqneH" and propose a respectful opening line for a diplomatic dispatch to Chancellor K''mpec.', '2369-04-14T10:00:00.000000+00:00', '2369-04-14T10:00:00.000000+00:00', '{"created_at":"2369-04-14T10:00:00.000000+00:00","index":0,"parent_message_uuid":null,"sender":"human","text":"Look up the Klingon greeting \\"nuqneH\\" and propose a respectful opening line for a diplomatic dispatch to Chancellor K''mpec.","truncated":false,"updated_at":"2369-04-14T10:00:00.000000+00:00","uuid":"30000001-1701-4d00-8000-000000030001"}', 'api', '2369-04-15T00:00:00+00:00');
