INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000004-1701-4d00-8000-00000000c004', '40000001-1701-4d00-8000-000000040001', NULL, 'human', 'What''s wrong with this medical-tricorder readout?', '2369-04-15T08:30:00.000000+00:00', '2369-04-15T08:30:00.000000+00:00', '{"created_at":"2369-04-15T08:30:00.000000+00:00","index":0,"parent_message_uuid":null,"sender":"human","text":"What''s wrong with this medical-tricorder readout?","truncated":false,"updated_at":"2369-04-15T08:30:00.000000+00:00","uuid":"40000001-1701-4d00-8000-000000040001"}', 'api', '2369-04-15T00:00:00+00:00');
INSERT INTO `anthropic_messages` (`conversation_uuid`, `message_uuid`, `parent_message_uuid`, `sender`, `text`, `created_at`, `updated_at`, `raw_json`, `source`, `last_seen_at`) VALUES ('c0000004-1701-4d00-8000-00000000c004', '40000002-1701-4d00-8000-000000040002', '40000001-1701-4d00-8000-000000040001', 'assistant', 'The readout shows elevated isoboramine (62 ng/mL; reference 35–40) and depressed serotonin uptake. Consistent with early-stage Vulcan neuro-pressure deficit. Recommend mind-meld therapy at 24h intervals.', '2369-04-15T08:30:45.000000+00:00', '2369-04-15T08:30:45.000000+00:00', '{"created_at":"2369-04-15T08:30:45.000000+00:00","index":1,"parent_message_uuid":"40000001-1701-4d00-8000-000000040001","sender":"assistant","text":"The readout shows elevated isoboramine (62 ng/mL; reference 35–40) and depressed serotonin uptake. Consistent with early-stage Vulcan neuro-pressure deficit. Recommend mind-meld therapy at 24h intervals.","truncated":false,"updated_at":"2369-04-15T08:30:45.000000+00:00","uuid":"40000002-1701-4d00-8000-000000040002"}', 'api', '2369-04-15T00:00:00+00:00');
